macro_rules! parse_line {
    ($t: ty) => ({
        let mut a_str = String::new();
        std::io::stdin().read_line(&mut a_str).expect("read error");
        let a_str = a_str.trim();
        a_str.parse::<$t>().expect("parse error")
    });
    ($($t: ty),+) => ({
        let mut a_str = String::new();
        std::io::stdin().read_line(&mut a_str).expect("read error");
        let mut a_iter = a_str.split_whitespace();
        (
            $(
            a_iter.next().unwrap().parse::<$t>().expect("parse error"),
            )+
        )
    })
}

macro_rules! parse_line_to_vec {
    ($t: ty) => {{
        let mut a_str = String::new();
        std::io::stdin().read_line(&mut a_str).expect("read error");
        (a_str
            .split_whitespace()
            .map(|x| x.parse::<$t>().unwrap())
            .collect::<Vec<$t>>())
    }};
}

fn solve() {
    let (a, b) = parse_line!(u64, u64);
    let mut pos = 0;
    let mut count = 0;
    while pos != a * b {
        let closest_a = (pos / a + 1) * a;
        let closest_b = (pos / b + 1) * b;
        if closest_a < closest_b {
            count += closest_a - pos;
            pos = closest_a;
        }else if closest_b < closest_a {
            pos = closest_b;
        }else if closest_a == closest_b {
            if a > b {
                count += closest_a - pos;
            }
            pos = closest_a;
        }
    }
    if count * 2 == a * b {
        println!("Equal");
    }else if count * 2 > a * b {
        println!("Dasha");
    }else{
        println!("Masha");
    }
}

fn main() {
    let tests = 1; // parse_line!(usize);
    for _ in 0..tests {
        solve();
    }
}
